import axios from 'axios';

// Upload file to IPFS via free IPFS service (temporary solution)
export async function uploadToIPFS(file) {
  try {
    const formData = new FormData();
    formData.append('file', file);

    // Using free IPFS service as temporary solution
    const response = await axios.post(
      'https://ipfs.io/api/v0/add',
      formData,
      {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      }
    );

    return `https://ipfs.io/ipfs/${response.data.Hash}`;
  } catch (error) {
    console.error('Error uploading to IPFS:', error);
    
    // Fallback: Create a data URL for demo purposes
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        resolve(reader.result);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  }
}

// Upload JSON metadata to IPFS via free IPFS service
export async function uploadMetadataToIPFS(metadata) {
  try {
    const formData = new FormData();
    const jsonBlob = new Blob([JSON.stringify(metadata)], { type: 'application/json' });
    formData.append('file', jsonBlob, 'metadata.json');

    // Using free IPFS service as temporary solution
    const response = await axios.post(
      'https://ipfs.io/api/v0/add',
      formData,
      {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      }
    );

    return `https://ipfs.io/ipfs/${response.data.Hash}`;
  } catch (error) {
    console.error('Error uploading metadata to IPFS:', error);
    
    // Fallback: Return base64 encoded metadata
    const metadataString = JSON.stringify(metadata);
    return `data:application/json;base64,${btoa(metadataString)}`;
  }
}
